INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ivamente, para menos, sem razão justificada, dos padrões de rendimento que razoavelmente possam permitir as manifestações de riqueza evidenciadas pelo sujeito passivo, nos termos do artigo 89.º-A.
