INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('soas que se encontrem nas condições definidas pelo artigo anterior, cujos rendimentos ilíquidos mensais não excedam 40  do valor do indexante de apoios sociais (IAS) ou 60  desse valor, tratando-se de casal. 
  2 - ... 
  3 - ... 
