INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' passivos abrangidos pelo regime simplificado de determinação do lucro tributável, cujo período de validade ainda esteja em curso no primeiro dia do período de tributação que se inicie em 2010, mantêm-se no regime simplificado de determinação do lucro tributável até ao final deste período, findo o qual se consideram abrangidos pelo artigo 9.º do Decreto-Lei n.º 158/2009, de 13 de Julho, caso se verifiquem os pressupostos nele previstos. 
  2 - Os sujeitos passivos referidos no número anterior podem optar pela aplicação das taxas constantes do n.º 1 do artigo 87.º do Código do IRC. 
  3 - A opção a que se refere o número anterior é exercida na declaração periódica de rendimentos a que se refere a alínea b) do n.º 1 do artigo 117.º do Código do IRC.            
         
   
     
                         
                          
