INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' à colecta por cada sujeito passivo com deficiência uma importância correspondente a quatro vezes o valor do IAS e por cada dependente com deficiência, bem como, por cada ascendente com deficiência que esteja nas condições da alínea e) do n.º 1 do Artigo 79.º, uma importância igual a 1,5 vezes o valor do IAS. 
