INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' 1 deixar de se verificar antes de completado o período de um ano, deve corrigir-se a dedução que tenha sido efectuada, sem prejuízo da consideração do crédito de imposto por dupla tributação internacional a que houver lugar, nos termos do disposto no Artigo 91.º 
